using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using System.Web.Mvc.Html;

public class ReviewController : Controller
{
    private readonly IReviewService _reviewService;

    public ReviewController(IReviewService reviewService)
    {
        _reviewService = reviewService;
    }

    public ActionResult Index(int productId)
    {
        var reviews = _reviewService.GetReviewsByProductId(productId);
        return View(reviews);
    }
}

public class ReviewViewModel
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string Title { get; set; }
    public string Content { get; set; }
    public int Rating { get; set; }
    public DateTime CreatedDate { get; set; }
    public string Author { get; set; }
}

public interface IReviewService
{
    IEnumerable<ReviewViewModel> GetReviewsByProductId(int productId);
}

public class ReviewService : IReviewService
{
    private readonly ApplicationDbContext _context;

    public ReviewService(ApplicationDbContext context)
    {
        _context = context;
    }

    public IEnumerable<ReviewViewModel> GetReviewsByProductId(int productId)
    {
        return _context.Reviews
            .Where(r => r.ProductId == productId)
            .Select(r => new ReviewViewModel
            {
                Id = r.Id,
                ProductId = r.ProductId,
                Title = r.Title,
                Content = r.Content,
                Rating = r.Rating,
                CreatedDate = r.CreatedDate,
                Author = r.Author
            })
            .ToList();
    }
}

@model IEnumerable<ReviewViewModel>

<div class="reviews">
    @foreach (var review in Model)
    {
        <div class="review">
            <h4>@Html.Encode(review.Title)</h4>
            <p class="author">By @Html.Encode(review.Author) on @review.CreatedDate.ToString("MM/dd/yyyy")</p>
            <div class="rating">Rating: @review.Rating/5</div>
            <div class="content">
                @Html.Raw(review.Content)
            </div>
        </div>
    }
</div>